Connection Socket::accept() const {
    if (!is_listening(fd_.unwrap())) {
        throw std::runtime_error("Socket is not in a listening state");
    }
    int new_fd = ::accept(fd_.unwrap(), nullptr, nullptr);
    if (new_fd == -1) {
        // Handle accept error
    }
    return Connection(FileDescriptor(new_fd));
}

Connection Socket::connect(std::string destination, uint16_t port) {
    if (destination == "localhost") {
        destination = "127.0.0.1";
    }
    sockaddr_in addr = {0};
    addr.sin_family = AF_INET;
    addr.sin_port = htons(port);
    if (inet_pton(AF_INET, destination.c_str(), &addr.sin_addr) <= 0) {
        struct hostent *he = gethostbyname(destination.c_str());
        if (he == nullptr) {
