        addr.sin_addr = *reinterpret_cast<in_addr *>(he->h_addr);
    }

    if (::connect(fd_.unwrap(), (struct sockaddr *)&addr, sizeof(addr)) == -1) {
        // Handle connect error
    }
    return Connection(std::move(fd_));
