Below is a full basic implementation of the `Socket` and `Server` classes as well as the utility function `is_listening`, based on the given header file structure. This example assumes that `Connection` class has at least a constructor that takes a `FileDescriptor`. Please note, for the full implementation to be production ready, other factors such as proper error handling, logging, thread-safety considerations, and extended functionality need to be included which may not be covered in this example. This implementation is intended for educational purposes to demonstrate how such classes might be architected.

**socket.cpp**

```cpp
#include "socket.h"
#include <cstring>
#include <stdexcept>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <netdb.h>
#include <unistd.h>

namespace net {

bool is_listening(int fd) {
    int val;
    socklen_t len = sizeof(val);
    if (getsockopt(fd, SOL_SOCKET, SO_ACCEPTCONN, &val, &len) == -1) {
        return false;
    }
    return val != 0;
}

Socket::Socket() : fd_(::socket(AF_INET, SOCK_STREAM, 0)) {
    if (fd().unwrap() == -1) {
        throw std::runtime_error("Failed to create socket");
    }
}

void Socket::listen(uint16_t port) const {
    sockaddr_in addr;
    std::memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons(port);
    addr.sin_addr.s_addr = INADDR_ANY;

    if (::bind(fd_.unwrap(), reinterpret_cast<struct sockaddr*>(&addr), sizeof(addr)) == -1) {
        throw std::runtime_error("Binding failed");
    }
    if (::listen(fd_.unwrap(), SOMAXCONN) == -1) {
        throw std::runtime_error("Listening failed");
    }
}

Connection Socket::accept() const {
    if (!is_listening(fd_.unwrap())) {
        throw std::runtime_error("Socket is not listening");
    }

    int client_fd = ::accept(fd_.unwrap(), nullptr, nullptr);
    if (client_fd == -1) {
        throw std::runtime_error("Failed to accept connection");
    }

    return Connection(FileDescriptor(client_fd));
}

Connection Socket::connect(const std::string& destination, uint16_t port) {
    struct sockaddr_in addr;
    std::memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons(port);

    if (destination == "localhost") {
        addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
    } else {
        if (inet_pton(AF_INET, destination.c_str(), &addr.sin_addr) <= 0) {
            struct hostent* host = gethostbyname(destination.c_str());
            if (!host) {
                throw std::runtime_error("DNS resolution failed");
            }
            addr.sin_addr = *reinterpret_cast<in_addr*>(host->h_addr);
        }
    }

    if (::connect(fd_.unwrap(), reinterpret_cast<struct sockaddr*>(&addr), sizeof(addr)) == -1) {
        throw std::runtime_error("Connection failed");
    }

    return Connection(FileDescriptor(fd_.unwrap()));
}

Connection Socket::connect(uint16_t port) {
    return connect("localhost", port);
}

int Socket::fd() const {
    return fd_.unwrap();
}

} // namespace net
